    def cheb(x1, y1, x2, y2):
        dx = x1 - x2
        if dx < 0: dx = -dx
        dy = y1 - y2
        if dy < 0: dy = -dy
        return dx if dx > dy else dy

    def best_resource_target():
        best = None
        best_key = None
        for rx, ry in res:
            d = cheb(sx, sy, rx, ry)
            if best is None or d < best_key[0] or (d == best_key[0] and (rx, ry) < best_key[1]):
